/**
 * Emits ir.ts — developer-facing namespace re-exporting factories with short names.
 *
 * Consumes NodeMap directly. Derives from factory exports — thin namespace wrapper.
 * No imports from node-model.ts or naming.ts.
 */

import type { NodeMap, AssembledNode, AssembledPolymorph } from '../compiler/rule.ts'

export interface EmitIrConfig {
    grammar: string
    nodeMap: NodeMap
}

export function emitIr(config: EmitIrConfig): string {
    const { nodeMap } = config

    const lines: string[] = [
        '// Auto-generated by @sittir/codegen — do not edit',
        '',
    ]

    // Collect factory imports. Every name surface comes off the node
    // itself now — no local shortening, no side-channel IrKeyMap.
    const factoryImports = new Set<string>()
    const fromImports = new Set<string>()

    for (const [kind, node] of nodeMap.nodes) {
        if (kind.startsWith('_')) continue
        if (!node.rawFactoryName) continue // supertype, token, hidden — no factory
        if (nodeMap.polymorphFormKinds.has(kind)) continue

        factoryImports.add(node.rawFactoryName)

        if (node.modelType === 'polymorph') {
            for (const form of node.forms) {
                if (form.rawFactoryName) factoryImports.add(form.rawFactoryName)
            }
        }

        if (node.modelType === 'branch' || node.modelType === 'container' || node.modelType === 'polymorph') {
            if (node.fromFunctionName) fromImports.add(node.fromFunctionName)
            if (node.modelType === 'polymorph') {
                for (const form of node.forms) {
                    if (form.fromFunctionName) fromImports.add(form.fromFunctionName)
                }
            }
        }
    }

    if (factoryImports.size > 0) {
        lines.push(`import { ${[...factoryImports].join(', ')} } from './factories.js';`)
    }
    if (fromImports.size > 0) {
        lines.push(`import { ${[...fromImports].join(', ')} } from './from.js';`)
    }
    lines.push('')

    // _attach helper — uses defineProperty with writable/configurable/enumerable
    // descriptors so Function's reserved read-only properties (name, length,
    // arguments, caller) don't throw. This matters for polymorphs whose form
    // name is a reserved word (e.g. typescript's importSpecifier has a
    // variant form named `name`). Object.assign uses [[Set]] which respects
    // the target's writable attribute, so it fails on these cases.
    // Spec 008 US4 / FR-025 considered replacing this with Object.assign —
    // rejected after discovering the Function-reserved-name collision at
    // TypeScript regen time. `_attach` stays.
    lines.push('function _attach<T extends (...args: never[]) => unknown, P extends Record<string, unknown>>(fn: T, props: P): T & P {')
    lines.push('  for (const key of Object.keys(props)) {')
    lines.push('    Object.defineProperty(fn, key, { value: props[key], writable: true, configurable: true, enumerable: true });')
    lines.push('  }')
    lines.push('  return fn as T & P;')
    lines.push('}')
    lines.push('')

    lines.push('export const ir = {')

    // Branch/container/polymorph factories — combined with .from()
    lines.push('  // Node factories')
    for (const [kind, node] of nodeMap.nodes) {
        if (kind.startsWith('_')) continue
        if (!node.irKey || !node.rawFactoryName || !node.fromFunctionName) continue
        if (!/^[A-Za-z_$][\w$]*$/.test(node.irKey)) continue
        if (node.modelType !== 'branch' && node.modelType !== 'container' && node.modelType !== 'polymorph') continue

        if (node.modelType === 'polymorph' && node.forms.length > 1) {
            const variantEntries = node.forms
                .filter(form => form.rawFactoryName && form.fromFunctionName)
                .map(form => `${JSON.stringify(form.name)}: _attach(${form.rawFactoryName}, { from: ${form.fromFunctionName} })`)
            lines.push(`  ${node.irKey}: _attach(${node.rawFactoryName}, { from: ${node.fromFunctionName}, ${variantEntries.join(', ')} }),`)
        } else {
            lines.push(`  ${node.irKey}: _attach(${node.rawFactoryName}, { from: ${node.fromFunctionName} }),`)
        }
    }

    lines.push('')

    // Keyword factories
    lines.push('  // Keyword factories')
    for (const [kind, node] of nodeMap.nodes) {
        if (kind.startsWith('_')) continue
        if (node.modelType !== 'keyword') continue
        if (!node.irKey || !node.rawFactoryName) continue
        if (!/^[A-Za-z_$][\w$]*$/.test(node.irKey)) continue
        lines.push(`  ${node.irKey}: ${node.rawFactoryName},`)
    }

    lines.push('')

    // Leaf factories
    lines.push('  // Leaf node factories')
    for (const [kind, node] of nodeMap.nodes) {
        if (kind.startsWith('_')) continue
        if (node.modelType !== 'leaf' && node.modelType !== 'enum') continue
        if (!node.irKey || !node.rawFactoryName) continue
        if (!/^[A-Za-z_$][\w$]*$/.test(node.irKey)) continue
        lines.push(`  ${node.irKey}: ${node.rawFactoryName},`)
    }

    lines.push('} as const;')
    return lines.join('\n')
}

